int largestSubarrayWithKDifference(vector<int> &arr, int k) {
   int n = arr.size(), j = 0;
   deque<int> decreasing, increasing;

   int maxLength = 0;

   for (int i  = 0; i < n; i++) {

      while (!decreasing.empty() && arr[i] > decreasing.back()) {
         decreasing.pop_back();
      }

      decreasing.push_back(arr[i]);

      while (!increasing.empty() && arr[i] < increasing.back()) {
         increasing.pop_back();
      }

      increasing.push_back(arr[i]);

      while (!decreasing.empty() && !increasing.empty() 
         && (decreasing.front() - increasing.front() ) > k) {

         if (decreasing.front() == arr[j])
            decreasing.pop_front();
         if (increasing.front() == arr[j])
            increasing.pop_front();

         j++;
      }

      maxLength = max(maxLength, i - j + 1);

   }

   return maxLength;
}
